installation.script:
#!/bin/bash
set -euo pipefail

mkdir -p /mnt/server/public /mnt/server/config /mnt/server/database /mnt/server/logs

if [ ! -f /mnt/server/public/index.php ]; then
cat > /mnt/server/public/index.php <<'PHP'
<?php
header('Content-Type: text/plain; charset=utf-8');

if (isset($_GET['webstack_rewrite'])) {
    echo "mod_rewrite=ok\n";
    exit;
}

echo "Pterodactyl Webstack OK\n";
echo "PHP=" . PHP_VERSION . "\n";
echo "Rewrite test: /__webstack/rewrite-test\n";
PHP
fi

if [ ! -f /mnt/server/public/.htaccess ]; then
cat > /mnt/server/public/.htaccess <<'HTACCESS'
RewriteEngine On
RewriteRule ^__webstack/rewrite-test/?$ index.php?webstack_rewrite=1 [END,QSA]
HTACCESS
fi

echo "Webstack server files prepared."
